def load_json(path:Path)->dict[str,Any]: return json.loads(path.read_text(encoding='utf-8'))
def build_input()->dict[str,Any]: return {'schema_version':'four_window_dashboard_route_integration_input_v1','task_id':TASK_ID,'generated_at':GENERATED_AT,'route_path':ROUTE_PATH,'source_preview_artifact':SOURCE_PREVIEW_ARTIFACT,'source_preview_html':SOURCE_PREVIEW_HTML,'controlled_route_only':True,'production_publish_allowed':False}
def _window_mapping(preview:dict[str,Any])->list[dict[str,Any]]:
    return [{'window_key':w.get('window_key'),'ui_window_id':w.get('ui_window_id'),'ui_display_name_zh':w.get('ui_display_name_zh'),'ui_display_name_en':w.get('ui_display_name_en'),'scheduled_time_tw':w.get('scheduled_time_tw'),'market_phase':w.get('market_phase'),'primary_purpose':w.get('primary_purpose'),'full_prediction_review_assigned':w.get('ui_window_id')=='prediction_review_1500'} for w in preview.get('four_window_content_contract',[])]
def build_artifact(payload:dict[str,Any]|None=None,repo_root:Path|None=None)->dict[str,Any]:
    repo_root=repo_root or Path.cwd(); payload=payload or build_input(); preview_ref=payload.get('source_preview_artifact',SOURCE_PREVIEW_ARTIFACT); html_ref=payload.get('source_preview_html',SOURCE_PREVIEW_HTML); preview=load_json(repo_root/preview_ref)
