def badge(status:str)->str: return 'safe' if status in {'fresh','always_current'} else 'warn' if status in {'stale','missing'} else ''
def cards(items:list[dict[str,Any]],kind:str)->str:
    out=[]
    for item in items:
        if not isinstance(item,dict): continue
        if kind=='report':
            title=item.get('report_window') or item.get('data_state') or 'report'; lines=[f"產生時間：{item.get('generated_timestamp') or 'missing'}",f"股票數：{item.get('stock_count') if item.get('stock_count') is not None else 'missing'}",f"已接區塊：{', '.join(item.get('report_sections_available') or ['資料待接'])}",f"缺少區塊：{', '.join(item.get('missing_sections') or ['無'])}",str(item.get('summary') or '')]; st=str(item.get('freshness_status') or 'missing')
        elif kind=='stock':
            title=f"{item.get('stock_id') or 'missing'} {item.get('stock_name') or ''}"; lines=[f"時間：{item.get('generated_at') or 'missing'}",f"分數：{item.get('total_score') if item.get('total_score') is not None else '資料待接'}",f"評等：{item.get('rating') or '資料待接'} / 動作：{item.get('action') or '資料待接'}",f"風險：{item.get('risk_summary') or '資料待接'}"]; st=str(item.get('freshness_status') or 'missing')
        elif kind=='field':
            title=item.get('label') or item.get('field') or 'field'; lines=[str(item.get('message') or item.get('data_state') or '資料待接')]; st=str(item.get('freshness_status') or 'missing')
        elif kind=='fresh':
            title=f"{item.get('category')} / {item.get('id')}"; lines=[f"timestamp: {item.get('timestamp') or 'missing'}",f"max age: {item.get('max_age_hours')}h"]; st=str(item.get('status') or 'missing')
        else:
            title=item.get('label') or item.get('source_family') or 'source'; lines=[f"可信度：{item.get('quality') or item.get('credibility')}",f"用途：{item.get('allowed_usage')}"]; st=str(item.get('freshness_status') or 'always_current')
        out.append('<div class="source-item"><h3>'+escape(str(title))+'</h3>'+''.join('<p>'+escape(str(x))+'</p>' for x in lines if x)+'<span class="badge '+badge(st)+'">'+escape(st)+'</span></div>')
    return ''.join(out) if out else '<div class="source-item"><h3>資料待接</h3><p>目前尚未找到可用資料。</p><span class="badge warn">missing</span></div>'
def render_route_html(artifact:dict[str,Any],preview_html:str)->str:
    runtime=load_json(REPO_ROOT/RUNTIME_DATA) if (REPO_ROOT/RUNTIME_DATA).exists() else {}; route_path=escape(str(artifact['route_path'])); status_map={'fresh':'資料正常','partial_data':'部分缺資料','stale':'資料過期','missing':'尚未接資料','preview_only':'預覽資料'}
    global_status=escape(status_map.get(str(runtime.get('global_freshness_status','preview_only')),'預覽資料')); latest_ts=escape(str(runtime.get('latest_data_timestamp') or '資料待接'))
    stocks=runtime.get('stock_universe',[]) if isinstance(runtime.get('stock_universe'),list) else []; stock_rows=[s for s in stocks if isinstance(s,dict) and s.get('stock_id')]; usable=len([s for s in stock_rows if s.get('data_state')=='usable']); missing=len(runtime.get('missing_data',[])) if isinstance(runtime.get('missing_data'),list) else 0; stale=len(runtime.get('stale_data',[])) if isinstance(runtime.get('stale_data'),list) else 0
    prediction_available='否，資料待接' if any(isinstance(p,dict) and p.get('freshness_status')=='missing' for p in runtime.get('prediction_fields',[])) else '是'
    window_cards=[]
    for w in runtime.get('four_windows',[]):
        if not isinstance(w,dict): continue
        purpose='Full prediction review / 完整盤後檢討' if w.get('full_prediction_review') else '查看此時段的決策資料狀態'
        if w.get('window_key')=='pre_close_1335': purpose='收盤快照；完整檢討待 15:00'
        window_cards.append(f'<article class="card window-card"><div class="window-time">{escape(str(w.get("expected_time")))}</div><div class="window-title">{escape(str(w.get("display_name")))}</div><p><strong>用途：</strong>{escape(purpose)}</p><p><strong>最新資料：</strong>{escape(str(w.get("latest_available_data_timestamp") or "資料待接"))}</p><p><strong>已接區塊：</strong>{escape(", ".join(w.get("available_sections") or ["目前尚未找到可用資料"]))}</p><p><strong>缺少區塊：</strong>{escape(", ".join(w.get("missing_sections") or ["無"]))}</p><p><strong>PM 動作：</strong>{escape(str(w.get("pm_readable_action")))}</p><span class="badge {badge(str(w.get("freshness_status")))}">{escape(str(w.get("freshness_label")))}</span></article>')
    stock_cards=[]
    for s in stock_rows[:12]: stock_cards.append(f'<div class="source-item"><h3>{escape(str(s.get("stock_id")))} {escape(str(s.get("stock_name") or ""))}</h3><p>來源：{escape(str(s.get("source") or s.get("source_artifact_or_table") or "資料待接"))}</p><p>更新：{escape(str(s.get("latest_report_timestamp") or s.get("last_updated") or "missing"))}</p><span class="badge {badge(str(s.get("freshness_status")))}">{escape(str(s.get("freshness_label")))}</span></div>')
    stock_html=''.join(stock_cards) if stock_cards else '<div class="source-item"><h3>資料待接</h3><p>目前尚未找到可用追蹤標的資料。</p></div>'
